import { IMessageComposer } from '@nitrots/nitro-renderer';

export class EditGangComposer implements IMessageComposer<any[]> {
    private _data: any[];

    /**
     * Edit an existing gang's appearance.
     * @param primaryColor Hex string (with or without '#'), e.g. "#FF0000" or "FF0000"
     * @param secondaryColor Hex string (with or without '#')
     * @param icon Icon id/slug (e.g. "crown") that maps to /icons/badges/{icon}.png
     */
    constructor(primaryColor: string, secondaryColor: string, icon: string) {
        this._data = [primaryColor, secondaryColor, icon];
        console.log('[📤] EditGangComposer packet sent:', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
